import{_ as a,o as i,c as e,a2 as s}from"./chunks/framework.CGYl2SZ_.js";const l=JSON.parse('{"title":"pairing","description":"pairing 页面","frontmatter":{"title":"pairing","description":"pairing 页面"},"headers":[],"relativePath":"channels/pairing.md","filePath":"channels/pairing.md"}');const n=a({name:"channels/pairing.md"},[["render",function(a,l,n,t,h,o){return i(),e("div",null,[...l[0]||(l[0]=[s('<h1 id="配对" tabindex="-1">配对 <a class="header-anchor" href="#配对" aria-label="Permalink to &quot;配对&quot;">​</a></h1><h1 id="配对-1" tabindex="-1">配对 <a class="header-anchor" href="#配对-1" aria-label="Permalink to &quot;配对&quot;">​</a></h1><p>&quot;配对&quot;是 OpenClaw 的明确<strong>所有者批准</strong>步骤。 它用于两个地方：</p><ol><li><strong>私信配对</strong>（谁允许与机器人交谈）</li><li><strong>节点配对</strong>（哪些设备/节点允许加入网关网络）</li></ol><p>安全上下文：<a href="/gateway/security.html">安全</a></p><h2 id="_1-私信配对-入站聊天访问" tabindex="-1">1) 私信配对（入站聊天访问） <a class="header-anchor" href="#_1-私信配对-入站聊天访问" aria-label="Permalink to &quot;1) 私信配对（入站聊天访问）&quot;">​</a></h2><p>当渠道配置为 DM 策略 <code>pairing</code> 时，未知发送者收到短代码，并且他们的消息<strong>不会被处理</strong>直到您批准。</p><p>默认 DM 策略记录在：<a href="/gateway/security.html">安全</a></p><p>配对代码：</p><ul><li>8 个字符，大写，无歧义字符（<code>0O1I</code>）。</li><li><strong>1 小时后过期</strong>。机器人仅在新请求创建时发送配对消息（大约每发送者每小时一次）。</li><li>待处理私信配对请求默认上限为<strong>每个渠道 3 个</strong>；额外请求被忽略直到一个过期或被批准。</li></ul><h3 id="批准发送者" tabindex="-1">批准发送者 <a class="header-anchor" href="#批准发送者" aria-label="Permalink to &quot;批准发送者&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">COD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>支持的渠道：<code>telegram</code>、<code>whatsapp</code>、<code>signal</code>、<code>imessage</code>、<code>discord</code>、<code>slack</code>、<code>feishu</code>。</p><h3 id="状态存储位置" tabindex="-1">状态存储位置 <a class="header-anchor" href="#状态存储位置" aria-label="Permalink to &quot;状态存储位置&quot;">​</a></h3><p>存储在 <code>~/.openclaw/credentials/</code>：</p><ul><li>待处理请求：<code>&lt;channel&gt;-pairing.json</code></li><li>批准的白名单存储： <ul><li>默认账户：<code>&lt;channel&gt;-allowFrom.json</code></li><li>非默认账户：<code>&lt;channel&gt;-&lt;accountId&gt;-allowFrom.json</code></li></ul></li></ul><p>账户作用域行为：</p><ul><li>非默认账户仅读写其作用域的白名单文件。</li><li>默认账户使用通道作用域的非作用域白名单文件。</li></ul><p>将这些视为敏感（它们控制对您助手的访问）。</p><h2 id="_2-节点设备配对-ios-android-macos-无头节点" tabindex="-1">2) 节点设备配对（iOS/Android/macOS/无头节点） <a class="header-anchor" href="#_2-节点设备配对-ios-android-macos-无头节点" aria-label="Permalink to &quot;2) 节点设备配对（iOS/Android/macOS/无头节点）&quot;">​</a></h2><p>节点作为具有 <code>role: node</code> 的<strong>设备</strong>连接到网关。网关创建设备配对请求，必须被批准。</p><h3 id="通过-telegram-配对-推荐用于-ios" tabindex="-1">通过 Telegram 配对（推荐用于 iOS） <a class="header-anchor" href="#通过-telegram-配对-推荐用于-ios" aria-label="Permalink to &quot;通过 Telegram 配对（推荐用于 iOS）&quot;">​</a></h3><p>如果您使用 <code>device-pair</code> 插件，您可以完全从 Telegram 进行首次设备配对：</p><ol><li>在 Telegram 中，向您的机器人发送消息：<code>/pair</code></li><li>机器人回复两条消息：一条说明消息和一条单独的<strong>设置代码</strong>消息（在 Telegram 中易于复制/粘贴）。</li><li>在您的手机上，打开 OpenClaw iOS 应用 → 设置 → 网关。</li><li>粘贴设置代码并连接。</li><li>回到 Telegram：<code>/pair approve</code></li></ol><p>设置代码是包含以下内容的 base64 编码 JSON 有效载荷：</p><ul><li><code>url</code>：网关 WebSocket URL（<code>ws://...</code> 或 <code>wss://...</code>）</li><li><code>bootstrapToken</code>：用于初始配对握手的短期单设备引导令牌</li></ul><p>在设置代码有效时，将其视为密码。</p><h3 id="批准节点设备" tabindex="-1">批准节点设备 <a class="header-anchor" href="#批准节点设备" aria-label="Permalink to &quot;批准节点设备&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reject</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h3 id="节点配对状态存储" tabindex="-1">节点配对状态存储 <a class="header-anchor" href="#节点配对状态存储" aria-label="Permalink to &quot;节点配对状态存储&quot;">​</a></h3><p>存储在 <code>~/.openclaw/devices/</code>：</p><ul><li><code>pending.json</code>（短期存在；待处理请求过期）</li><li><code>paired.json</code>（已配对设备 + 令牌）</li></ul><p>注意：</p><ul><li>传统 <code>node.pair.*</code> API（CLI：<code>openclaw nodes pending/approve</code>）是单独的网关拥有的配对存储。WS 节点仍然需要设备配对。</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li>安全模型 + 提示注入：<a href="/gateway/security.html">安全</a></li><li>安全更新（运行 doctor）：<a href="/install/updating.html">更新</a></li><li>渠道配置： <ul><li>Telegram：<a href="/channels/telegram.html">Telegram</a></li><li>WhatsApp：<a href="/channels/whatsapp.html">WhatsApp</a></li><li>Signal：<a href="/channels/signal.html">Signal</a></li><li>BlueBubbles (iMessage)：<a href="/channels/bluebubbles.html">BlueBubbles</a></li><li>iMessage（传统）：<a href="/channels/imessage.html">iMessage</a></li><li>Discord：<a href="/channels/discord.html">Discord</a></li><li>Slack：<a href="/channels/slack.html">Slack</a></li></ul></li></ul>',36)])])}]]);export{l as __pageData,n as default};
